// tsconfig.json
{
  "compilerOptions": {
    "strict": true,

    // What "strict" expands to (these are the defaults when strict is true):
    // "strictNullChecks": true,
    // "strictFunctionTypes": true,
    // "strictBindCallApply": true,
    // "strictPropertyInitialization": true,
    // "noImplicitAny": true,
    // "noImplicitThis": true,
    // "alwaysStrict": true,
    // "useUnknownInCatchVariables": true   (added in TS 4.4)
  }
}

// strictNullChecks: false (dangerous default before strict)
let name: string = null;  // allowed — null assignable to string
name.toUpperCase();       // TypeScript says OK, runtime crashes

// strictNullChecks: true (strict mode)
let name: string = null;  // Error: Type 'null' is not assignable to type 'string'
let name2: string | null = null; // OK — explicit

// Narrowing is now required before use
function greet(user: { name: string } | null): string {
  // return user.name.toUpperCase(); // Error: 'user' is possibly 'null'
  return user?.name.toUpperCase() ?? 'Guest'; // OK — handled
}

// Angular: HttpClient responses and async values benefit most
@Component({ /* ... */ })
export class UserComponent {
  user: User | null = null; // explicit — null is a valid state

  ngOnInit(): void {
    this.userService.getUser().subscribe(u => this.user = u);
  }
}

// noImplicitAny: false
function process(data) { // data: any — silently loses all type info
  return data.value;     // any — no errors even if data has no .value
}

// noImplicitAny: true
function process(data) { // Error: Parameter 'data' implicitly has an 'any' type
  return data.value;
}

// Fix: annotate parameters
function process(data: { value: string }): string {
  return data.value; // now type-safe
}

// Also catches: untyped array destructuring, catch bindings (see useUnknownInCatchVariables)
const [first] = []; // first: any — error with noImplicitAny

// strictPropertyInitialization: true
class UserComponent {
  // Error: Property 'userId' has no initializer and is not definitely assigned in the constructor
  userId: string;

  // Fix 1: initialize directly
  userId: string = '';

  // Fix 2: initialize in constructor
  constructor(private route: ActivatedRoute) {
    this.userId = this.route.snapshot.params['id'];
  }
}

// Angular @Input pattern: use definite assignment assertion or initializer
@Component({ selector: 'app-user', template: '...' })
export class UserComponent {
  @Input({ required: true }) user!: User; // ! = "I guarantee this will be set before use"
  @Input() title = 'Default Title';       // initializer — no ! needed
}

// Angular 17+ signal inputs don't need !
@Component({ /* ... */ })
export class UserComponent {
  user = input.required<User>(); // required signal — no property init issue
}

type Handler<T> = (value: T) => void;

// strictFunctionTypes: false (unsafe)
const handleAnimal: Handler<Animal> = (a: Animal) => console.log(a.name);
const handleDog: Handler<Dog> = handleAnimal; // allowed, but wrong at runtime if Dog has extra fields

// strictFunctionTypes: true
const handleAnimal: Handler<Animal> = (a: Animal) => console.log(a.name);
const handleDog: Handler<Dog> = handleAnimal;
// Error: Type 'Handler<Animal>' is not assignable to type 'Handler<Dog>'

// Angular: correct typing for event callbacks and RxJS operators
const mapToString: (x: string | number) => string = String; // OK — parameter is wider
const mapToNumber: (x: number) => number = parseFloat;     // OK — exact match

// Before TS 4.4 (or strict: false): catch e is any
try {
  await fetch('/api/data');
} catch (e) {
  console.log(e.message); // no error — but e might not have .message at runtime
}

// useUnknownInCatchVariables: true
try {
  await fetch('/api/data');
} catch (e) {
  // e is unknown — must narrow before access
  if (e instanceof Error) {
    console.log(e.message); // OK after narrowing
  } else {
    console.log(String(e)); // handle non-Error throws
  }
}

// Angular HttpErrorResponse pattern
catchError((e: unknown) => {
  if (e instanceof HttpErrorResponse) {
    return throwError(() => new Error(e.error?.message ?? 'HTTP error'));
  }
  return throwError(() => e);
})

// Step 1: enable one flag at a time in tsconfig.json
{
  "compilerOptions": {
    // Start with the highest-value flag
    "strictNullChecks": true
    // Add more once the above is clean:
    // "noImplicitAny": true,
    // "strictPropertyInitialization": true,
    // etc.
  }
}

// File-level: disable strict for an entire file
// @ts-nocheck

// Line-level: suppress a single error (next line only)
// @ts-ignore
const x: string = null; // null in a context where strictNullChecks is on

// Property-level: definite assignment assertion
class Service {
  client!: HttpClient; // tells TS "I know this will be set before any method runs"
}

// Angular: when migrating a large codebase, create a separate tsconfig
// tsconfig.legacy.json — extends base, but strict: false for old files
{
  "extends": "./tsconfig.json",
  "compilerOptions": { "strict": false },
  "include": ["src/app/legacy/**"]
}

import { signal, computed } from '@angular/core';

// Signal<User | null> — null is explicit and must be handled downstream
const currentUser = signal<User | null>(null);

// computed that consumes the signal — must handle null
const displayName = computed(() => currentUser()?.name ?? 'Guest');
//                                               ^ ?. required with strictNullChecks

// toSignal from HttpClient — starts as undefined
const users = toSignal(this.userService.getAll());
// users: Signal<User[] | undefined>

// Use with || in template
// {{ users() | json }}  — or guard in template:
// @if (users(); as u) { ... }
